INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (2115, 213765, 6, 1933, '从&#183;学生&#183;到&#183;白领', '从来没有想过自己竟然会如此的幸运，刚刚从学校毕业便找到了工作。而我也从学生变成了一个真正的白领，从前总觉得“白领”这个词是多么遥不可及，是许多年轻人的梦而我？居然如此幸运的成为了一位真正的白领&#183;&#183;&#183;&#183;&#183;带着许多人羡慕的眼光走进公司，穿着白领的代表--职业套装
<br>，那种优越感从心里冒出。从小，父母总是说我没有前途，上学的时候因为书读的不好，总有一些自以为是的人看不起。然而现在，看着他们羡慕的眼光，心里的那种虚荣到了极点&#183;&#183;&#183;&#183;&#183;&#183;也许现在有人说我是幸福的，是幸运的，但在我看来这不过只是外表而已。在我的心里我渴望能有一份真正的爱情，能有一个属于我的家。也许现在对我来说那是很遥远的
<br>，朋友说我不只外表变成熟了，就连内心也开始老了！也许吧，终于体会到了，真正的社会是什么样了，什么才叫生活，什么是爱情的资源了&#183;&#183;&#183;&#183;&#183;&#183;
<br>哎&#183;&#183;&#183;&#183;&#183;&#183;&#183;&#183;&#183;&#183;&#183;无聊死了，不知道写什么，呵呵~！也许没有人看得明白~！！！', '从来没有想过自己竟然会如此的幸运，刚刚从学校毕业便找到了工作。而我也从学生变成了一个真正的白领，从前总觉得“白领”这个词是多么遥不可及，是许多年轻人的梦而我？居然如此幸运的成为了一位真正的白领·····带着许多人羡慕的眼光走进公司，穿着白领的代表--职业套装

